circular_leo:
Create Spacecraft Sat;
Sat.DisplayStateType = Keplerian;
Sat.SMA = 6878;
Sat.ECC = 0.001;
Sat.INC = 28.5;
Sat.RAAN = 0;
Sat.AOP = 0;
Sat.TA = 0;

Create ForceModel FM;
FM.PrimaryBodies = {Earth};

Create Propagator Prop;
Prop.FM = FM;

Create ReportFile rf;
rf.Filename = 'leo.report';
rf.Add = {Sat.Earth.RMAG};

BeginMissionSequence;
Propagate Prop(Sat) {Sat.ElapsedSecs = 5400};
Report rf Sat.Earth.RMAG;

persistent_target:
Create Spacecraft Sat;
Sat.DisplayStateType = Keplerian;
Sat.SMA = 7000;
Sat.ECC = 0.001;
Sat.INC = 28.5;

Create ForceModel FM;
FM.PrimaryBodies = {Earth};

Create Propagator Prop;
Prop.FM = FM;

Create ImpulsiveBurn dv;
dv.Axes = VNB;

Create DifferentialCorrector DC;

Create ReportFile rf;
rf.Filename = 'apogee.report';
rf.Add = {Sat.Earth.RMAG};

BeginMissionSequence;
Target DC;
   Vary DC(dv.Element1 = 0.005, {Perturbation = 1e-5, Lower = 0, Upper = 0.01, MaxStep = 0.002});
   Maneuver dv(Sat);
   Propagate Prop(Sat) {Sat.Apoapsis};
   Achieve DC(Sat.Earth.RMAG = 80000, {Tolerance = 0.1});
EndTarget;
Report rf Sat.Earth.RMAG;

